const globalStore = $getWorkflowStaticData('global');
const STALE_MS = 15 * 60 * 1000;
const lock = globalStore._enriching;
if (lock && (Date.now() - lock.startedAt) < STALE_MS) {
  return [{ json: { already_running: true, total: 0, leads: [] } }];
}

const sheet1Raw = $('Read Sheet Rows').first().json;
const [headers, ...rows] = sheet1Raw.values || [[]];

const dmRaw = $input.first().json;
const dmAllRows = (dmRaw.error || !dmRaw.values) ? [] : (dmRaw.values || []);
const enrichedPlaceIds = new Set();
dmAllRows.forEach((row, i) => {
  if (i === 0) return;
  const placeId = (row && row[0]) || '';
  if (placeId) enrichedPlaceIds.add(placeId);
});

const onlyMissing = $('Webhook').first().json.body?.only_missing !== false;
const leads = rows
  .map((row, i) => ({
    ...Object.fromEntries(headers.map((h, j) => [h, row[j] || ''])),
    _rowNumber: i + 2
  }))
  .filter(lead => !onlyMissing || !enrichedPlaceIds.has(lead.place_id));

if (leads.length === 0) {
  return [{ json: { already_running: false, total: 0, leads: [] } }];
}

globalStore._enriching = { executionId: $execution.id, startedAt: Date.now() };
return [{ json: { already_running: false, total: leads.length, leads } }];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
delete store[execId];
delete store._enriching;
return [];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
if (!store[execId]) store[execId] = {};
const lead = $input.first().json;
store[execId].pendingLead = { _rowNumber: lead._rowNumber, place_id: lead.place_id || '', name: lead.name || '' };
store[execId].leadInfo = { name: lead.name || '', address: lead.address || '', phone: lead.phone || '', website: lead.website || '' };
const location = (lead.address || '').split(',').slice(-2).join(',').trim();
const domain = lead.website ? lead.website.replace(/^https?:\/\//, '').replace(/\/.*$/, '') : '';
const websitePart = domain ? ' ' + domain : '';
const query = '"' + (lead.name || '') + '" ' + location + websitePart + ' owner founder CEO director manager LinkedIn email phone';
return [{ json: { serpapi_query: { api_key: $env.SERPAPI_API_KEY, q: query.trim(), num: '10' } }}];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
if (!store[execId]) store[execId] = {};
const leadInfo = store[execId].leadInfo || {};
const broadResults = $input.first().json;
store[execId].broadResults = broadResults;
let secondQuery;
let domain = '';
if (leadInfo.website) {
  domain = leadInfo.website.replace(/^https?:\/\//, '').replace(/\/.*$/, '');
  secondQuery = 'site:' + domain + ' owner founder director manager team about contact email phone';
} else {
  const location = (leadInfo.address || '').split(',').slice(-2).join(',').trim();
  secondQuery = '"' + (leadInfo.name || '') + '" ' + location + ' owner founder director manager LinkedIn Facebook';
}
const firstPageText = JSON.stringify((broadResults.organic_results || []).slice(0, 5));
const hasDecisionHint = /\b(owner|founder|ceo|director|manager|principal|partner|practice manager)\b/i.test(firstPageText);
const hasOfficialDomain = domain ? firstPageText.toLowerCase().includes(domain.toLowerCase()) : false;
const needsTargetedSearch = !hasDecisionHint || (domain && !hasOfficialDomain);
return [{ json: { needs_targeted_search: needsTargetedSearch, serpapi_site_query: { api_key: $env.SERPAPI_API_KEY, q: secondQuery.trim(), num: '10' }}}];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const leadInfo = store[execId]?.leadInfo || {};
const broadResult = store[execId]?.broadResults || {};
const siteResult = $input.first().json;
function extractContext(result) {
  const parts = [];
  if (result.error) parts.push('Search error: ' + result.error);
  if (result.answer_box) parts.push('Answer box: ' + JSON.stringify(result.answer_box).substring(0, 700));
  if (result.knowledge_graph) parts.push('Knowledge graph: ' + JSON.stringify(result.knowledge_graph).substring(0, 900));
  const organic = (result.organic_results || []).slice(0, 8).map(r => [r.title, r.link, r.snippet, r.rich_snippet ? JSON.stringify(r.rich_snippet).substring(0, 300) : ''].filter(Boolean).join('\n')).join('\n---\n');
  if (organic) parts.push('Organic results:\n' + organic);
  return parts.join('\n\n').substring(0, 5000);
}
const broadContext = extractContext(broadResult);
const siteContext = extractContext(siteResult);
const contextBlock = [broadContext, siteContext ? '=== Targeted Search ===\n' + siteContext : ''].filter(Boolean).join('\n\n');
const prompt = 'Business: ' + (leadInfo.name || 'N/A') + ', ' + (leadInfo.address || 'N/A') + '\nWebsite: ' + (leadInfo.website || 'N/A') + '\n\nSerpApi Google search results:\n' + (contextBlock || 'No results') + '\n\nExtract every supported key decision maker for this business, up to 5 people. Prefer owner, founder, CEO, managing director, director, general manager, principal, partner, or practice manager. Use ONLY the search results above. Do not guess. Return N/A for fields not supported by results.\n\nReturn JSON only in this exact shape: {"people":[{"person_name":"N/A","person_title":"N/A","person_phone":"N/A","person_email":"N/A","person_linkedin":"N/A","person_instagram":"N/A","person_twitter":"N/A"}]}';
return [{ json: { llm_body: { model: 'gpt-4o-mini', max_tokens: 900, temperature: 0.1, response_format: { type: 'json_object' }, messages: [{ role: 'user', content: prompt }] }}}];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const pendingLead = store[execId]?.pendingLead || {};
if (store[execId]) delete store[execId].pendingLead;

const response = $input.first().json;
const choices = response?.choices;
const text = choices?.[0]?.message?.content?.trim() || '';

if (response?.error || !choices || !Array.isArray(choices) || choices.length === 0 || !text) {
  return [{ json: { ...pendingLead, _should_update: false } }];
}

function clean(value) {
  const v = String(value || '').trim();
  return /^n\/a$/i.test(v) || !v ? 'N/A' : v.substring(0, 500);
}

function extract(label) {
  const m = text.match(new RegExp(label + ':\\s*(.+)', 'i'));
  return m ? clean(m[1]) : 'N/A';
}

let people = [];
try {
  const parsed = JSON.parse(text);
  people = Array.isArray(parsed.people) ? parsed.people : [];
} catch (e) {
  people = [{
    person_name: extract('PERSON_NAME'),
    person_title: extract('PERSON_TITLE'),
    person_phone: extract('PERSON_PHONE'),
    person_email: extract('PERSON_EMAIL'),
    person_linkedin: extract('PERSON_LINKEDIN'),
    person_instagram: extract('PERSON_INSTAGRAM'),
    person_twitter: extract('PERSON_TWITTER')
  }];
}

const seen = new Set();
const rows = people
  .map(person => ({
    ...pendingLead,
    person_name: clean(person.person_name),
    person_title: clean(person.person_title),
    person_phone: clean(person.person_phone),
    person_email: clean(person.person_email),
    person_linkedin: clean(person.person_linkedin),
    person_instagram: clean(person.person_instagram),
    person_twitter: clean(person.person_twitter),
    _should_update: true
  }))
  .filter(person => person.person_name !== 'N/A')
  .filter(person => {
    const key = [person.person_name, person.person_title, person.person_email, person.person_linkedin].join('|').toLowerCase();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .slice(0, 5);

if (rows.length === 0) return [{ json: { ...pendingLead, _should_update: false } }];
return rows.map(row => ({ json: row }));

const raw = $input.first().json;
const allRows = (raw.error || !raw.values) ? [] : (raw.values || []);
const dm = {};
allRows.forEach((row, i) => {
  if (i === 0) return;
  const placeId = (row && row[0]) || '';
  if (placeId) {
    if (!dm[placeId]) dm[placeId] = [];
    dm[placeId].push({
      person_name:      (row[2] || ''),
      person_title:     (row[3] || ''),
      person_phone:     (row[4] || ''),
      person_email:     (row[5] || ''),
      person_linkedin:  (row[6] || ''),
      person_instagram: (row[7] || ''),
      person_twitter:   (row[8] || '')
    });
  }
});
return [{ json: { dm } }];
